require_once __DIR__.'/../includes/config.php';require_admin();$id=(int)($_GET['id']??0);$s=db()->prepare('SELECT o.*,u.name AS customer_name,u.email FROM orders o JOIN users u ON u.id=o.user_id WHERE o.id=?');$s->bind_param('i',$id);$s->execute();$order=$s->get_result()->fetch_assoc();$s->close();if(!$order){http_response_code(404);exit('Pesanan tidak ditemukan.');}$i=db()->prepare('SELECT * FROM order_items WHERE order_id=?');$i->bind_param('i',$id);$i->execute();$items=$i->get_result();$pageTitle='Detail Pesanan';require __DIR__.'/admin_header.php';
?>
<div class="section-head"><div><span class="eyebrow">Detail Pesanan</span><h1><?= e($order['invoice_number']) ?></h1></div><span class="status status-<?= e($order['status']) ?>"><?= e(ucfirst($order['status'])) ?></span></div><div class="order-detail-grid"><div class="panel"><h3>Item Pesanan</h3><?php while($item=$items->fetch_assoc()): ?><div class="order-line"><div><strong><?= e($item['product_name']) ?></strong><small>Ukuran <?= e($item['size']) ?> · <?= (int)$item['quantity'] ?> item</small></div><strong><?= rupiah($item['subtotal']) ?></strong></div><?php endwhile; ?><hr><div class="summary-row total"><span>Total</span><strong><?= rupiah($order['total_amount']) ?></strong></div></div><div class="panel"><h3>Customer dan Pengiriman</h3><p><strong><?= e($order['customer_name']) ?></strong><br><?= e($order['email']) ?></p><p><strong>Penerima:</strong> <?= e($order['recipient_name']) ?><br><strong>Telepon:</strong> <?= e($order['phone']) ?></p><p><?= nl2br(e($order['shipping_address'])) ?></p><p><strong>Metode:</strong> <?= e(strtoupper($order['payment_method'])) ?></p><?php if($order['notes']): ?><p><strong>Catatan:</strong> <?= e($order['notes']) ?></p><?php endif; ?></div></div>
